async (params, browser) => {
  // Open Figma recents
  await browser.open('https://www.figma.com/files/recents')

  // Wait for file cards to load
  await browser.waitForSelector('[data-testid=\'file-card\'], .file_card, .file-browser-page--files .tile', 15000)

  // Let file thumbnails render
  await browser.wait(3000)

  // Scrape recent file cards
  const result = await browser.evaluate(`const files = []; const cards = document.querySelectorAll('[data-testid="file-card"], .file_card, .file-browser-page--files .tile'); for (let i = 0; i < Math.min(cards.length, 20); i++) { const card = cards[i]; const nameEl = card.querySelector('.file-name, [data-testid="filename"], [class*="file_name"]'); const linkEl = card.querySelector('a[href*="/design/"], a[href*="/file/"]'); const thumbEl = card.querySelector('img[src*="figma"], img[class*="thumbnail"]'); const timeEl = card.querySelector('time, [class*="last_modified"], [class*="timestamp"]'); files.push({ name: nameEl ? nameEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', thumbnail: thumbEl ? thumbEl.src : '', last_modified: timeEl ? (timeEl.getAttribute('datetime') || timeEl.textContent.trim()) : '' }); } return { file_count: files.length, files: files }`)

  return result
}
